# P1: 2 people, capacity 1
def solve_p1():
    initial = (0, 0, 'L')  # A, B on left (0), boat on left
    target = (1, 1, 'R')

    from collections import deque
    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, dist = queue.popleft()
        a_pos, b_pos, boat = state
        if (a_pos, b_pos, boat) == target:
            return dist

        # Can take 1 person (capacity 1)
        for person in [0, 1]:  # 0=A, 1=B
            p_pos = a_pos if person == 0 else b_pos
            if p_pos == boat:  # person on same side as boat
                new_a = a_pos
                new_b = b_pos
                if person == 0:
                    new_a = 1 - p_pos
                else:
                    new_b = 1 - p_pos
                new_boat = 1 - boat
                new_state = (new_a, new_b, new_boat)
                if new_state not in visited:
                    visited.add(new_state)
                    queue.append((new_state, dist + 1))
    return None

print(f'P1: {solve_p1()}')

# P2: 3 people, capacity 2
def solve_p2():
    initial = (0, 0, 0, 'L')
    target = (1, 1, 1, 'R')

    from collections import deque
    from itertools import combinations
    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, dist = queue.popleft()
        a_pos, b_pos, c_pos, boat = state
        if (a_pos, b_pos, c_pos, boat) == target:
            return dist

        people = [a_pos, b_pos, c_pos]
        for take in [1, 2]:
            for indices in combinations([0,1,2], take):
                if all(people[i] == boat for i in indices):
                    new_pos = list(people)
                    for i in indices:
                        new_pos[i] = 1 - boat
                    new_boat = 1 - boat
                    new_state = tuple(new_pos) + (new_boat,)
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, dist + 1))
    return None

print(f'P2: {solve_p2()}')

# P3: 4 people, capacity 2
def solve_p3():
    initial = (0, 0, 0, 0, 'L')
    target = (1, 1, 1, 1, 'R')

    from collections import deque
    from itertools import combinations
    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, dist = queue.popleft()
        positions = list(state[:-1])
        boat = state[-1]
        if positions == [1,1,1,1] and boat == 'R':
            return dist

        for take in [1, 2]:
            for indices in combinations([0,1,2,3], take):
                if all(positions[i] == boat for i in indices):
                    new_pos = positions.copy()
                    for i in indices:
                        new_pos[i] = 1 - boat
                    new_boat = 1 - boat
                    new_state = tuple(new_pos) + (new_boat,)
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, dist + 1))
    return None

print(f'P3: {solve_p3()}')

# P4: Wolf, Goat, Cabbage with Farmer
def solve_p4():
    initial = (0, 0, 0, 0, 'L')  # wolf, goat, cabbage, farmer positions, boat
    target = (1, 1, 1, 1, 'R')

    from collections import deque
    from itertools import combinations

    def check_safe(w, g, cab, f):
        # Determine items on each bank
        left = []
        right = []
        for pos, name in [(w, 'W'), (g, 'G'), (cab, 'C')]:
            if pos == 0:
                left.append(name)
            else:
                right.append(name)

        # Check left (no farmer = danger if alone)
        if f == 1:  # farmer on right
            if 'W' in left and 'G' in left:
                return False
            if 'G' in left and 'C' in left:
                return False
        # Check right
        if f == 0:  # farmer on left
            if 'W' in right and 'G' in right:
                return False
            if 'G' in right and 'C' in right:
                return False
        return True

    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, dist = queue.popleft()
        wolf, goat, cabbage, farmer, boat = state
        if (wolf, goat, cabbage, farmer) == (1, 1, 1, 1) and boat == 'R':
            return dist

        # Items on boat side
        boat_side = 0 if boat == 'L' else 1
        items_on_boat_side = []
        for i, pos in enumerate([wolf, goat, cabbage]):
            if pos == boat_side:
                items_on_boat_side.append(i)

        # Can take 0 or 1 item (farmer always goes)
        for num_take in [0, 1]:
            if num_take > len(items_on_boat_side):
                continue
            for item_indices in combinations(items_on_boat_side, num_take):
                new_wolf = wolf
                new_goat = goat
                new_cabbage = cabbage
                new_farmer = 1 - farmer

                for idx in item_indices:
                    if idx == 0:
                        new_wolf = 1 - wolf
                    elif idx == 1:
                        new_goat = 1 - goat
                    else:
                        new_cabbage = 1 - cabbage

                if check_safe(new_wolf, new_goat, new_cabbage, new_farmer):
                    new_state = (new_wolf, new_goat, new_cabbage, new_farmer, 1 - boat if boat == 'L' else 'L' if boat == 'R' else None)
                    new_boat_side = 'R' if boat == 'L' else 'L'
                    new_state = (new_wolf, new_goat, new_cabbage, new_farmer, new_boat_side)
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, dist + 1))
    return None

print(f'P4: {solve_p4()}')
